import logging
from dataclasses import dataclass, field
from typing import Dict, List, Optional, Tuple, Any
from enum import Enum

logger = logging.getLogger(__name__)

class ModelSizeClass(Enum):
    """Model size classifications for optimization"""
    TINY = "tiny"      # 1B-1.1B parameters
    SMALL = "small"    # 2B-3B parameters
    MEDIUM = "medium"  # 7B-9B parameters
    LARGE = "large"    # 13B-30B parameters
    XLARGE = "xlarge"  # 70B+ parameters

@dataclass
class ModelProfile:
    """Performance profile for a specific model"""
    size_class: ModelSizeClass
    optimal_params: Dict[str, Any]
    performance_profile: Dict[str, Dict[str, Any]]
    timeout_profile: Dict[str, float]
    benchmark_scores: Dict[str, float] = field(default_factory=dict)
    optimization_notes: List[str] = field(default_factory=list)

@dataclass
class OptimizationResult:
    """Result of model optimization"""
    optimized_config: Dict[str, Any]
    applied_optimizations: List[str]
    expected_performance: Dict[str, float]
    estimated_speedup: float
    memory_efficiency: float

