    def get_model_profile(self, model_name: str) -> Optional[ModelProfile]:
        """Get profile for specific model"""
        # Direct match first
        if model_name in self.model_profiles:
            return self.model_profiles[model_name]

        # Pattern matching for variants
        for profile_name, profile in self.model_profiles.items():
            if any(part in model_name.lower() for part in profile_name.split(':')):
                logger.info(f"Using profile '{profile_name}' for model '{model_name}'")
                return profile

        return None

    def get_optimized_config(self, model_name: str, task_type: str, base_config: Dict[str, Any],
                           context_info: Dict[str, Any] = None) -> OptimizationResult:
        """
        Get optimized configuration for model and task
        Reference: Context Scoring Systempt2.txt optimization techniques
        """

        # Get model profile
        profile = self.get_model_profile(model_name)
        if not profile:
            profile = self._get_default_profile(model_name)

        # Get task optimization
        task_opts = self.task_optimizations.get(task_type, self.task_optimizations['structured_tasks'])

        # Start with base configuration
        optimized_config = base_config.copy()
        applied_optimizations = []

        # Apply model-specific optimizations
        model_task_config = profile.performance_profile.get(task_type, profile.optimal_params)

        for param, value in model_task_config.items():
            if param != 'focus':  # Skip non-parameter keys
                optimized_config[param] = value
                applied_optimizations.append(f"Applied {param}={value} for {task_type}")

        # Apply task-specific modifications
        if 'temperature' in optimized_config:
            original_temp = optimized_config['temperature']

            if 'temperature_reduction' in task_opts:
                optimized_config['temperature'] = max(0.1, original_temp * (1 - task_opts['temperature_reduction']))
                applied_optimizations.append(f"Reduced temperature by {task_opts['temperature_reduction']:.0%}")

            elif 'temperature_boost' in task_opts:
                optimized_config['temperature'] = min(1.0, original_temp * (1 + task_opts['temperature_boost']))
                applied_optimizations.append(f"Increased temperature by {task_opts['temperature_boost']:.0%}")

        # Apply token optimizations
        if 'max_tokens' in optimized_config:
            original_tokens = optimized_config['max_tokens']

            if 'token_efficiency' in task_opts:
                optimized_config['max_tokens'] = int(original_tokens * task_opts['token_efficiency'])
                applied_optimizations.append(f"Adjusted tokens: {original_tokens} -> {optimized_config['max_tokens']}")

            elif 'token_expansion' in task_opts:
                optimized_config['max_tokens'] = int(original_tokens * task_opts['token_expansion'])
                applied_optimizations.append(f"Expanded tokens: {original_tokens} -> {optimized_config['max_tokens']}")

        # Apply timeout optimization
        if task_type in profile.timeout_profile:
            optimized_config['timeout'] = profile.timeout_profile[task_type]
            applied_optimizations.append(f"Set timeout to {optimized_config['timeout']}s for {task_type}")

        # Context-aware optimizations
        if context_info:
            context_opts, context_applied = self._apply_context_optimizations(
                optimized_config, context_info, profile, task_type
            )
            optimized_config.update(context_opts)
            applied_optimizations.extend(context_applied)

        # Calculate expected performance improvements
        expected_performance = self._estimate_performance_improvement(
            profile, task_type, applied_optimizations
        )

        # Estimate speedup and efficiency
        estimated_speedup = self._calculate_speedup_estimate(profile, task_type, applied_optimizations)
        memory_efficiency = self._calculate_memory_efficiency(profile, optimized_config)

        return OptimizationResult(
            optimized_config=optimized_config,
            applied_optimizations=applied_optimizations,
            expected_performance=expected_performance,
            estimated_speedup=estimated_speedup,
            memory_efficiency=memory_efficiency
        )

    def _get_default_profile(self, model_name: str) -> ModelProfile:
        """Create default profile for unknown models"""

        # Infer size class from model name
        size_class = ModelSizeClass.SMALL  # Default

        name_lower = model_name.lower()
        if any(indicator in name_lower for indicator in ['1b', 'tiny']):
            size_class = ModelSizeClass.TINY
        elif any(indicator in name_lower for indicator in ['7b', '8b', '9b']):
            size_class = ModelSizeClass.MEDIUM
        elif any(indicator in name_lower for indicator in ['13b', '15b', '20b', '30b']):
            size_class = ModelSizeClass.LARGE
        elif any(indicator in name_lower for indicator in ['70b', '120b']):
            size_class = ModelSizeClass.XLARGE

        # Default configurations by size class
        size_defaults = {
            ModelSizeClass.TINY: {
                'optimal_params': {'temperature': 0.4, 'max_tokens': 1024, 'top_p': 0.8},
                'timeout_profile': {'base_timeout': 30.0, 'structured': 8.0, 'deliberate': 15.0, 'recall': 3.0}
            },
            ModelSizeClass.SMALL: {
                'optimal_params': {'temperature': 0.6, 'max_tokens': 2048, 'top_p': 0.85},
                'timeout_profile': {'base_timeout': 60.0, 'structured': 10.0, 'deliberate': 25.0, 'recall': 5.0}
            },
            ModelSizeClass.MEDIUM: {
                'optimal_params': {'temperature': 0.7, 'max_tokens': 4096, 'top_p': 0.9},
                'timeout_profile': {'base_timeout': 120.0, 'structured': 15.0, 'deliberate': 45.0, 'recall': 8.0}
            },
            ModelSizeClass.LARGE: {
                'optimal_params': {'temperature': 0.8, 'max_tokens': 8192, 'top_p': 0.95},
                'timeout_profile': {'base_timeout': 180.0, 'structured': 20.0, 'deliberate': 60.0, 'recall': 10.0}
            },
            ModelSizeClass.XLARGE: {
                'optimal_params': {'temperature': 0.9, 'max_tokens': 16384, 'top_p': 0.95},
                'timeout_profile': {'base_timeout': 300.0, 'structured': 30.0, 'deliberate': 90.0, 'recall': 15.0}
            }
        }

        defaults = size_defaults[size_class]

        return ModelProfile(
            size_class=size_class,
            optimal_params=defaults['optimal_params'],
            performance_profile={
                'structured_tasks': {**defaults['optimal_params'], 'temperature': defaults['optimal_params']['temperature'] * 0.7},
                'reasoning_tasks': {**defaults['optimal_params'], 'temperature': defaults['optimal_params']['temperature'] * 1.1},
                'recall_tasks': {**defaults['optimal_params'], 'temperature': defaults['optimal_params']['temperature'] * 0.5, 'max_tokens': 64},
                'tool_use': {**defaults['optimal_params'], 'temperature': defaults['optimal_params']['temperature'] * 0.8}
            },
            timeout_profile=defaults['timeout_profile'],
            optimization_notes=[f"Generated default profile for {size_class.value} class model"]
        )

    def _apply_context_optimizations(self, config: Dict[str, Any], context_info: Dict[str, Any],
                                   profile: ModelProfile, task_type: str) -> Tuple[Dict[str, Any], List[str]]:
        """Apply context-aware optimizations"""
        optimizations = {}
        applied = []

        # Context length optimization
        context_length = context_info.get('context_length', 0)
        if context_length > 1000:
            # Long context - reduce max_tokens to leave room
            if 'max_tokens' in config:
                reduction = min(0.3, (context_length - 1000) / 2000)  # Up to 30% reduction
                new_tokens = int(config['max_tokens'] * (1 - reduction))
                optimizations['max_tokens'] = new_tokens
                applied.append(f"Reduced max_tokens by {reduction:.0%} for long context ({context_length} chars)")

        # History depth optimization
        history_depth = context_info.get('history_depth', 0)
        if history_depth > 10:
            # Deep history - slightly reduce temperature for consistency
            if 'temperature' in config:
                temp_reduction = min(0.1, history_depth / 100)
                optimizations['temperature'] = max(0.1, config['temperature'] - temp_reduction)
                applied.append(f"Reduced temperature for deep history ({history_depth} entries)")

        # Model loading state optimization
        if context_info.get('model_cold_start', False):
            # Cold start - extend timeout
            if 'timeout' in config:
                optimizations['timeout'] = config['timeout'] * 1.5
                applied.append("Extended timeout for cold model start")

        return optimizations, applied

    def _estimate_performance_improvement(self, profile: ModelProfile, task_type: str,
                                        optimizations: List[str]) -> Dict[str, float]:
        """Estimate performance improvements from optimizations"""
        improvements = {
            'quality_score': 1.0,      # Baseline
            'response_time': 1.0,      # Baseline
            'consistency': 1.0,        # Baseline
            'accuracy': 1.0           # Baseline
        }

        # Apply improvement estimates based on optimizations
        for opt in optimizations:
            if 'temperature' in opt.lower() and 'reduced' in opt.lower():
                improvements['consistency'] *= 1.15  # 15% improvement in consistency
                improvements['accuracy'] *= 1.1     # 10% improvement in accuracy

            elif 'timeout' in opt.lower():
                improvements['response_time'] *= 1.2  # 20% better response time handling

            elif 'tokens' in opt.lower() and 'reduced' in opt.lower():
                improvements['response_time'] *= 1.3  # 30% faster responses

            elif task_type == 'structured' and 'format' in opt.lower():
                improvements['quality_score'] *= 1.25  # 25% quality improvement for structured

        # Apply model class bonuses
        if profile.size_class == ModelSizeClass.TINY:
            improvements['response_time'] *= 1.5  # Tiny models are much faster
        elif profile.size_class == ModelSizeClass.SMALL:
            improvements['response_time'] *= 1.3  # Small models are faster
        elif profile.size_class == ModelSizeClass.MEDIUM:
            improvements['quality_score'] *= 1.2  # Medium models have better quality

        return improvements

    def _calculate_speedup_estimate(self, profile: ModelProfile, task_type: str,
                                  optimizations: List[str]) -> float:
        """Calculate estimated speedup from optimizations"""
        base_speedup = 1.0

        # Model size class speedups
        size_speedups = {
            ModelSizeClass.TINY: 2.5,
            ModelSizeClass.SMALL: 1.8,
            ModelSizeClass.MEDIUM: 1.3,
            ModelSizeClass.LARGE: 1.0,
            ModelSizeClass.XLARGE: 0.8
        }

        base_speedup *= size_speedups.get(profile.size_class, 1.0)

        # Task-specific speedups
        task_speedups = {
            'recall': 1.5,      # Recall tasks are faster
            'structured': 1.3,  # Structured tasks are more efficient
            'tool_use': 1.1,    # Tool coordination has moderate speedup
            'reasoning': 0.9    # Reasoning tasks are slower but thorough
        }

        base_speedup *= task_speedups.get(task_type, 1.0)

        # Optimization bonuses
        for opt in optimizations:
            if 'reduced' in opt.lower() and 'tokens' in opt.lower():
                base_speedup *= 1.2
            elif 'timeout' in opt.lower():
                base_speedup *= 1.1

        return base_speedup

    def _calculate_memory_efficiency(self, profile: ModelProfile, config: Dict[str, Any]) -> float:
        """Calculate memory efficiency score"""
        base_efficiency = 1.0

        # Model size efficiency
        size_efficiency = {
            ModelSizeClass.TINY: 1.8,
            ModelSizeClass.SMALL: 1.5,
            ModelSizeClass.MEDIUM: 1.2,
            ModelSizeClass.LARGE: 1.0,
            ModelSizeClass.XLARGE: 0.7
        }

        base_efficiency *= size_efficiency.get(profile.size_class, 1.0)

        # Token usage efficiency
        max_tokens = config.get('max_tokens', 2048)
        if max_tokens < 1000:
            base_efficiency *= 1.3  # Very efficient
        elif max_tokens < 2000:
            base_efficiency *= 1.1  # Moderately efficient

        return base_efficiency

